// frontend/src/components/importacion/StepIndicator.jsx
import React from 'react';

const StepIndicator = ({ currentStep, handleStepChange }) => {
  return (
    <div className="flex justify-center">
      <div className="inline-flex items-center max-w-md">
        {/* Step 1 */}
        <div 
          className={`flex flex-col items-center cursor-pointer ${currentStep >= 1 ? 'text-purple-700' : 'text-gray-400'}`}
          onClick={() => currentStep > 1 && handleStepChange(1)}
        >
          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white font-bold ${currentStep >= 1 ? 'bg-purple-700' : 'bg-gray-300'}`}>
            1
          </div>
          <span className="text-xs mt-1">Importación</span>
        </div>
        
        {/* Connection line 1-2 (más corta) */}
        <div className="w-32 mx-1 h-0.5 relative">
          <div className="absolute inset-0 bg-gray-200"></div>
          <div 
            className="absolute inset-0 bg-purple-700 transition-all duration-300"
            style={{ width: currentStep >= 2 ? '100%' : '0%' }}
          ></div>
        </div>
        
        {/* Step 2 */}
        <div 
          className={`flex flex-col items-center cursor-pointer ${currentStep >= 2 ? 'text-purple-700' : 'text-gray-400'}`}
          onClick={() => currentStep > 2 && handleStepChange(2)}
        >
          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white font-bold ${currentStep >= 2 ? 'bg-purple-700' : 'bg-gray-300'}`}>
            2
          </div>
          <span className="text-xs mt-1">Validación</span>
        </div>
        
        {/* Connection line 2-3 (más corta) */}
        <div className="w-32 mx-1 h-0.5 relative">
          <div className="absolute inset-0 bg-gray-200"></div>
          <div 
            className="absolute inset-0 bg-purple-700 transition-all duration-300"
            style={{ width: currentStep >= 3 ? '100%' : '0%' }}
          ></div>
        </div>
        
        {/* Step 3 */}
        <div 
          className={`flex flex-col items-center cursor-pointer ${currentStep >= 3 ? 'text-purple-700' : 'text-gray-400'}`}
          onClick={() => currentStep > 3 && handleStepChange(3)}
        >
          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white font-bold ${currentStep >= 3 ? 'bg-purple-700' : 'bg-gray-300'}`}>
            3
          </div>
          <span className="text-xs mt-1">Resultado</span>
        </div>
      </div>
    </div>
  );
};

export default StepIndicator;
